// Stop execution if today is not a NYSE trading day
const now = new Date();

// Weekend check (0=Sun, 6=Sat)
const dow = now.getUTCDay();
if (dow === 0 || dow === 6) return [];

const year  = now.getUTCFullYear();
const month = String(now.getUTCMonth() + 1).padStart(2, '0');
const date  = String(now.getUTCDate()).padStart(2, '0');
const today = year + '-' + month + '-' + date;

//                  Helpers                 
function nthWeekday(y, m, wd, n) {
  const d = new Date(Date.UTC(y, m, 1));
  let count = 0;
  while (d.getUTCMonth() === m) {
    if (d.getUTCDay() === wd && ++count === n) return d;
    d.setUTCDate(d.getUTCDate() + 1);
  }
}
function lastWeekday(y, m, wd) {
  const d = new Date(Date.UTC(y, m + 1, 0));
  while (d.getUTCDay() !== wd) d.setUTCDate(d.getUTCDate() - 1);
  return d;
}
function observed(y, m, day) {
  const d  = new Date(Date.UTC(y, m, day));
  const wd = d.getUTCDay();
  if (wd === 6) d.setUTCDate(day - 1);
  if (wd === 0) d.setUTCDate(day + 1);
  return d;
}
function fmt(d) {
  return d.getUTCFullYear() + '-' +
    String(d.getUTCMonth() + 1).padStart(2, '0') + '-' +
    String(d.getUTCDate()).padStart(2, '0');
}
// Easter / Good Friday
function goodFriday(y) {
  const a=y%19,b=Math.floor(y/100),c=y%100,d=Math.floor(b/4),e=b%4;
  const f=Math.floor((b+8)/25),g=Math.floor((b-f+1)/3);
  const h=(19*a+b-d-g+15)%30,i=Math.floor(c/4),k=c%4;
  const l=(32+2*e+2*i-h-k)%7,m=Math.floor((a+11*h+22*l)/451);
  const mo=Math.floor((h+l-7*m+114)/31),da=((h+l-7*m+114)%31)+1;
  const easter=new Date(Date.UTC(y,mo-1,da));
  easter.setUTCDate(easter.getUTCDate()-2);
  return easter;
}

//                  NYSE Holidays                 
const holidays = new Set([
  fmt(observed(year, 0,  1)),          // New Year's Day
  fmt(nthWeekday(year, 0,  1, 3)),     // MLK Day                 3rd Mon Jan
  fmt(nthWeekday(year, 1,  1, 3)),     // Presidents Day          3rd Mon Feb
  fmt(goodFriday(year)),               // Good Friday
  fmt(lastWeekday(year, 4,  1)),       // Memorial Day            last Mon May
  fmt(observed(year, 5,  19)),         // Juneteenth
  fmt(observed(year, 6,  4)),          // Independence Day
  fmt(nthWeekday(year, 8,  1, 1)),     // Labor Day               1st Mon Sep
  fmt(nthWeekday(year, 10, 4, 4)),     // Thanksgiving            4th Thu Nov
  fmt(observed(year, 11, 25)),         // Christmas
]);

if (holidays.has(today)) return [];

return [{ json: {} }];

const LIMIT = 1900;
const chunks = [];

// 1. AI analysis from LLM node (plain text)
const rawAnalysis = $input.first().json.text || '';
const analysis = rawAnalysis.replace(/^[.\s"{}]+/, '').replace(/["\s{}]+$/, '').trim();
if (analysis) {
  chunks.push(analysis);
}

// 2. Formatted brief from Compute1 directly (LLM node doesn't pass it through)
const brief = $('Compute1').first().json.message || '';
if (!brief) return chunks.map(c => ({ json: { message: c } }));

if (brief.length <= LIMIT) {
  chunks.push(brief);
} else {
  // Strip outer ``` wrappers, split at section boundaries, re-wrap each chunk
  const inner = brief.replace(/^```\n/, '').replace(/\n```$/, '');
  const sections = inner.split('\n\n');
  let cur = '';

  for (const sec of sections) {
    const candidate = cur ? cur + '\n\n' + sec : sec;
    // Reserve 8 chars for ``` wrapping
    if (candidate.length > LIMIT - 8 && cur) {
      chunks.push('```\n' + cur.trim() + '\n```');
      cur = sec;
    } else {
      cur = candidate;
    }
  }
  if (cur.trim()) {
    chunks.push('```\n' + cur.trim() + '\n```');
  }
}

return chunks.map(c => ({ json: { message: c } }));

const data    = $json.marketData;
const today   = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const r    = n => (n !== null && n !== undefined && !isNaN(n)) ? Math.round(n * 100) / 100 : null;
const sign = n => (n !== null && n >= 0) ? "+" : "";
const pct  = n => n !== null ? sign(n) + n + "%" : "N/A";
const pad  = (s, len) => String(s).padEnd(len);
const arr  = n => (n !== null && n > 0.05) ? "^" : (n !== null && n < -0.05) ? "v" : "-";

// -- Assets --
const find  = sym => data.find(d => d.symbol === sym);
const es    = find("ES=F");
const nq    = find("NQ=F");
const ym    = find("YM=F");
const rty   = find("RTY=F");
const spy   = find("SPY");
const qqq   = find("QQQ");
const iwm   = find("IWM");
const dia   = find("DIA");
const rsp   = find("RSP");
const smh   = find("SMH");
const iyt   = find("IYT");
const vix   = find("^VIX");
const tnx   = find("^TNX");
const tlt   = find("TLT");
const hyg   = find("HYG");
const dxy   = find("DX-Y.NYB");
const gold  = find("GC=F");
const oil   = find("CL=F");
const btc   = find("BTC-USD");
const eth   = find("ETH-USD");

const sectors       = data.filter(d => d.category === "Sector");
const sectorsSorted = [...sectors].sort((a, b) => (b.percentChange || 0) - (a.percentChange || 0));

const OFFENSIVE = ["XLK","XLY","XLF","XLI","XLB","XLE"];
const DEFENSIVE = ["XLU","XLRE","XLP","XLV","XLC"];

const SECTOR_LABELS = {
  "XLK":  "Technology",
  "XLY":  "Consumer Discr.",
  "XLF":  "Financials",
  "XLI":  "Industrials",
  "XLB":  "Materials",
  "XLE":  "Energy",
  "XLV":  "Healthcare",
  "XLU":  "Utilities",
  "XLRE": "Real Estate",
  "XLP":  "Consumer Staples",
  "XLC":  "Comm. Services",
};

// -- Data source label --
const preMarketCount = data.filter(d => d.priceSource === "PRE-MARKET").length;
const dataLabel = preMarketCount >= 3
  ? "LIVE PRE-MARKET (" + preMarketCount + " assets)"
  : "YESTERDAY'S CLOSE";

// -- Risk Score (-5 to +5) --
let riskScore = 0;
const riskFactors = [];

const futsValid = [es, nq, rty].filter(f => f && f.percentChange !== null);
if (futsValid.length) {
  const futAvg = r(futsValid.reduce((s, f) => s + f.percentChange, 0) / futsValid.length);
  if      (futAvg >= 0.5)   { riskScore += 2; riskFactors.push("Futures +" + futAvg + "%"); }
  else if (futAvg >= 0.15)  { riskScore += 1; riskFactors.push("Futures +" + futAvg + "%"); }
  else if (futAvg <= -0.5)  { riskScore -= 2; riskFactors.push("Futures " + futAvg + "%"); }
  else if (futAvg <= -0.15) { riskScore -= 1; riskFactors.push("Futures " + futAvg + "%"); }
  else                      { riskFactors.push("Futures flat"); }
}

const vixLevel = vix?.price ? r(vix.price) : 20;
if      (vixLevel < 15) { riskScore += 2; riskFactors.push("VIX " + vixLevel + " calm"); }
else if (vixLevel < 20) { riskScore += 1; riskFactors.push("VIX " + vixLevel + " normal"); }
else if (vixLevel < 25) { riskScore -= 1; riskFactors.push("VIX " + vixLevel + " elevated"); }
else                    { riskScore -= 2; riskFactors.push("VIX " + vixLevel + " fear"); }

const breadthDiff = (rsp?.percentChange != null && spy?.percentChange != null)
  ? r(rsp.percentChange - spy.percentChange) : 0;
if      (breadthDiff >= 0.2)  { riskScore += 1; riskFactors.push("breadth +" + breadthDiff + "%"); }
else if (breadthDiff <= -0.2) { riskScore -= 1; riskFactors.push("breadth " + breadthDiff + "%"); }

if (hyg?.percentChange != null && tlt?.percentChange != null) {
  if      (hyg.percentChange > 0.3  && tlt.percentChange < 0)   { riskScore += 1; riskFactors.push("credit compressing"); }
  else if (hyg.percentChange < -0.5 && tlt.percentChange > 0.3) { riskScore -= 1; riskFactors.push("credit widening"); }
}

if (tnx?.percentChange != null) {
  if      (tnx.percentChange > 1)  riskFactors.push("10Y ^" + pct(r(tnx.percentChange)));
  else if (tnx.percentChange < -1) riskFactors.push("10Y v" + pct(r(tnx.percentChange)));
}

riskScore = Math.max(-5, Math.min(5, riskScore));

// -- Verdict --
let riskVerdict, riskEmoji, riskDesc;
if      (riskScore >= 3)  { riskVerdict = "RISK-ON";          riskEmoji = ":green_circle:";  riskDesc = "Favour longs. Size up on breakouts."; }
else if (riskScore >= 1)  { riskVerdict = "LEANING RISK-ON";  riskEmoji = ":yellow_circle:"; riskDesc = "Mild tailwind. Selective longs only."; }
else if (riskScore === 0) { riskVerdict = "MIXED";            riskEmoji = ":white_circle:";  riskDesc = "No edge. Reduce size, wait for clarity."; }
else if (riskScore >= -2) { riskVerdict = "LEANING RISK-OFF"; riskEmoji = ":orange_circle:"; riskDesc = "Defensive lean. Reduce exposure."; }
else                      { riskVerdict = "RISK-OFF";         riskEmoji = ":red_circle:";    riskDesc = "Stay defensive. Cash is a position."; }

const absScore = Math.abs(riskScore);
const scoreBar = riskScore >= 0
  ? "[" + ".".repeat(5 - absScore) + "#".repeat(absScore) + "]"
  : "[" + "#".repeat(absScore) + ".".repeat(5 - absScore) + "]";

// -- Leadership Signal --
const spyChg = spy?.percentChange ?? 0;
const qqqChg = qqq?.percentChange ?? 0;
const iwmChg = iwm?.percentChange ?? 0;
const rspChg = rsp?.percentChange ?? 0;
const broadAvg = r((iwmChg + rspChg) / 2);
const allDown = spyChg < -0.3 && qqqChg < -0.3 && iwmChg < -0.3;
const megaCapLead = r(qqqChg - broadAvg) > 0.5;
const broadParticipation = Math.abs(r(broadAvg - spyChg)) < 0.3 && spyChg > 0;

let leadership;
if (allDown)                 leadership = "Broad Selling";
else if (megaCapLead)        leadership = "Mega Cap Driven";
else if (broadParticipation) leadership = "Broad Participation";
else                         leadership = "Mixed";

// -- Breadth Summary --
const positiveSectors  = sectors.filter(s => s.percentChange > 0).length;
const sectorBreadthPct = positiveSectors / sectors.length;
const iwmVsSpy         = r(iwmChg - spyChg);
const avgBreadthDiff   = r((breadthDiff + iwmVsSpy) / 2);

let breadthSummary;
if      (avgBreadthDiff >= 0.15 && sectorBreadthPct > 0.6)   breadthSummary = "Strong";
else if (avgBreadthDiff <= -0.15 || sectorBreadthPct < 0.35) breadthSummary = "Weak";
else                                                           breadthSummary = "Neutral";

// -- Liquidity Signal --
const dxyChg = dxy?.percentChange ?? 0;
const tnxChg = tnx?.percentChange ?? 0;
const hygChg = hyg?.percentChange ?? 0;
let liquidityScore = 0;
if (dxyChg < -0.2) liquidityScore++; else if (dxyChg > 0.2)  liquidityScore--;
if (tnxChg < -1)   liquidityScore++; else if (tnxChg > 1)    liquidityScore--;
if (hygChg > 0.2)  liquidityScore++; else if (hygChg < -0.3) liquidityScore--;

let liquiditySignal;
if      (liquidityScore >= 2)  liquiditySignal = "Expanding";
else if (liquidityScore <= -2) liquiditySignal = "Tightening";
else                           liquiditySignal = "Neutral";

// -- Text signals --
const breadthSignal = breadthDiff >= 0.2
  ? "BROAD +" + breadthDiff + "% RSP lead"
  : breadthDiff <= -0.2
    ? "NARROW " + breadthDiff + "% RSP lag"
    : "NEUTRAL";

const creditSignal = (hyg?.percentChange != null && tlt?.percentChange != null)
  ? hyg.percentChange < -0.5 && tlt.percentChange > 0.3 ? "WIDENING (!)"
  : hyg.percentChange > 0.3  && tlt.percentChange < 0   ? "COMPRESSING (ok)"
  : "NEUTRAL"
  : "N/A";

// -- Sector focus & rotation --
const top5symbols   = sectorsSorted.slice(0, 5).map(s => s.symbol);
const rotationScore = top5symbols.reduce((score, sym) => {
  if (OFFENSIVE.includes(sym)) return score + 1;
  if (DEFENSIVE.includes(sym)) return score - 1;
  return score;
}, 0);
const rotationBias = rotationScore >= 2 ? "Cyclical"
  : rotationScore <= -2 ? "Defensive"
  : "Mixed";

let focusSectors;
if      (riskScore >= 1)  focusSectors = sectorsSorted.filter(s => OFFENSIVE.includes(s.symbol)).slice(0, 3);
else if (riskScore <= -1) focusSectors = sectorsSorted.filter(s => DEFENSIVE.includes(s.symbol)).slice(0, 3);
else                      focusSectors = sectorsSorted.slice(0, 3);
const focusSymbols = new Set(focusSectors.map(s => s.symbol));

// -- TABLES --
const futRows = [es, nq, ym, rty].filter(Boolean).map(f =>
  arr(f.percentChange) + " " + pad(f.symbol, 8) +
  pad(f.price != null ? String(r(f.price)) : "N/A", 10) +
  pad(pct(r(f.percentChange)), 9) +
  (f.gapPct != null ? "gap " + pct(f.gapPct) : "")
);
const futuresTable = "```\n  FUTURES  PRICE     CHG      GAP\n" + futRows.join("\n") + "\n```";

const idxRows = [spy, qqq, iwm, dia, rsp].filter(Boolean).map(d =>
  arr(d.percentChange) + " " + pad(d.symbol, 6) +
  pad(d.price != null ? String(r(d.price)) : "N/A", 10) +
  pad(pct(r(d.percentChange)), 9) +
  (d.gapPct != null ? "gap " + pct(d.gapPct) : "")
);
const vixRow = "- " + pad("VIX", 6) +
  pad(vix?.price != null ? String(r(vix.price)) : "N/A", 10) +
  pct(r(vix?.percentChange));

const leaderRows = [smh, iyt].filter(Boolean).map(d =>
  arr(d.percentChange) + " " + pad(d.symbol, 6) +
  pad(d.price != null ? String(r(d.price)) : "N/A", 10) +
  pad(pct(r(d.percentChange)), 9)
);
const leaderSection = leaderRows.length
  ? "\n  -- Leadership --\n" + leaderRows.join("\n")
  : "";

const indexTable = "```\n  TICKER  PRICE     CHG      GAP\n" +
  idxRows.join("\n") + "\n" + vixRow + leaderSection + "\n```";

const top4       = sectorsSorted.slice(0, 4);
const bottom3    = sectorsSorted.slice(-3);
const displaySet = new Set([...top4, ...bottom3].map(s => s.symbol));
focusSectors.forEach(s => displaySet.add(s.symbol));
const sectorDisplay = sectorsSorted.filter(s => displaySet.has(s.symbol));
const topDisplay = sectorDisplay.filter(s => sectorsSorted.indexOf(s) < 4);
const botDisplay = sectorDisplay.filter(s => sectorsSorted.indexOf(s) >= 4);
const sectorLabel = sym => SECTOR_LABELS[sym] || sym;

const topRows = topDisplay.map(s =>
  arr(s.percentChange) + " " + pad(sectorLabel(s.symbol), 18) +
  pad(pct(r(s.percentChange)), 9) + (focusSymbols.has(s.symbol) ? " <" : "")
);
const botRows = botDisplay.map(s =>
  arr(s.percentChange) + " " + pad(sectorLabel(s.symbol), 18) +
  pad(pct(r(s.percentChange)), 9) + (focusSymbols.has(s.symbol) ? " <" : "")
);
const sectorTable = "```\n  SECTOR             CHG\n" +
  topRows.join("\n") + "\n  -------------------------\n" +
  botRows.join("\n") + "\n```";

const riskAssetRows = [
  { d: gold, label: "Gold  " },
  { d: oil,  label: "Oil   " },
  { d: btc,  label: "BTC   " },
  { d: eth,  label: "ETH   " },
].filter(x => x.d && x.d.price != null).map(x =>
  arr(x.d.percentChange) + " " + x.label + " " +
  pad(String(r(x.d.price)), 10) +
  pct(r(x.d.percentChange))
);
const riskAssetsTable = "```\n  ASSET   PRICE     CHG\n" + riskAssetRows.join("\n") + "\n```";

const liquidityRows = [
  { d: tnx, label: "10Y   " },
  { d: dxy, label: "DXY   " },
  { d: hyg, label: "Credit" },
].filter(x => x.d && x.d.price != null).map(x =>
  arr(x.d.percentChange) + " " + x.label + " " +
  pad(String(r(x.d.price)), 10) +
  pct(r(x.d.percentChange))
);
const liquidityTable = "```\n  ASSET   PRICE     CHG\n" + liquidityRows.join("\n") + "\n```";

// -- Message --
const msgLines = [
  "```",
  today + "  PRE-MARKET BRIEF | " + dataLabel,
  "=========================",
  riskVerdict + " " + scoreBar + " " + riskDesc,
  "Signals    " + riskFactors.join("  |  "),
  "Breadth    " + breadthSummary + "  (" + breadthSignal + ")",
  "Credit     " + creditSignal,
  "Leadership " + leadership,
  "Liquidity  " + liquiditySignal,
  "",
  " Futures ",
  "  FUTURES  PRICE     CHG      GAP",
  futRows.join("\n"),
  "",
  " Indexes & Leadership ",
  "  TICKER  PRICE     CHG      GAP",
  idxRows.join("\n"),
  vixRow,
];
if (leaderRows.length) {
  msgLines.push("  -- Leadership --");
  leaderRows.forEach(lr => msgLines.push(lr));
}
msgLines.push(
  "",
  " Sector Rotation ",
  "  SECTOR             CHG",
  topRows.join("\n"),
  "  -------------------------",
  botRows.join("\n"),
  " Rotation: " + rotationBias + " | Focus: " + [...focusSymbols].join(", "),
  "",
  " Risk Assets ",
  "  ASSET   PRICE     CHG",
  riskAssetRows.join("\n"),
  "",
  " Liquidity ",
  "  ASSET   PRICE     CHG",
  liquidityRows.join("\n"),
  " Liquidity: " + liquiditySignal,
  "```"
);
const message = msgLines.join("\n");

// -- Save row --
const sectorBySymbol = {};
sectors.forEach(s => { sectorBySymbol[s.symbol] = s; });

const sectorRanking = sectorsSorted
  .map((s, i) => (i+1) + ". " + s.symbol + "(" + (s.percentChange >= 0 ? "+" : "") + r(s.percentChange) + "%)")
  .join(", ");
const top3Sectors = sectorsSorted.slice(0, 3)
  .map(s => s.symbol + "(" + (s.percentChange >= 0 ? "+" : "") + r(s.percentChange) + "%)").join(", ");
const bot3Sectors = sectorsSorted.slice(-3)
  .map(s => s.symbol + "(" + r(s.percentChange) + "%)").join(", ");

const riskAssetsList = [gold, oil, btc, eth].filter(x => x && x.percentChange != null);
const riskAvg = riskAssetsList.length
  ? r(riskAssetsList.reduce((sum, x) => sum + x.percentChange, 0) / riskAssetsList.length)
  : null;
const riskAssetsTrend = riskAvg === null ? "N/A"
  : riskAvg > 0.2 ? "Bullish"
  : riskAvg < -0.2 ? "Bearish"
  : "Neutral";

const saveRow = {
  Date:            today,
  Type:            "PRE-MARKET",
  Timestamp:       new Date().toISOString(),
  DataSource:      dataLabel,
  MarketRegime:    riskVerdict,
  RiskVerdict:     riskVerdict,
  RiskScore:       riskScore,
  RiskFactors:     riskFactors.join(" | "),
  VIX:             vixLevel,
  Regime:          vixLevel >= 20 ? "ELEVATED" : "NORMAL",
  Leadership:      leadership,
  Rotation:        rotationBias,
  Breadth:         breadthSummary,
  Liquidity:       liquiditySignal,
  BreadthSignal:   breadthSignal,
  CreditSignal:    creditSignal,
  FocusSectors:    [...focusSymbols].join(", "),
  RotationBias:    rotationBias,
  RotationScore:   rotationScore,
  SectorRanking:   sectorRanking,
  Top3Sectors:     top3Sectors,
  Bot3Sectors:     bot3Sectors,
  TopSectors:      top3Sectors,
  WeakSectors:     bot3Sectors,
  RiskAssetsTrend: riskAssetsTrend,
  ES_Price:        es?.price,
  ES_Change:       es?.percentChange,
  NQ_Change:       nq?.percentChange,
  SPY_Price:       spy?.price,
  SPY_Change:      spy?.percentChange,
  QQQ_Change:      qqq?.percentChange,
  IWM_Change:      iwm?.percentChange,
  Gold_Change:     gold?.percentChange,
  Oil_Change:      oil?.percentChange,
  BTC_Change:      btc?.percentChange,
  ETH_Change:      eth?.percentChange,
  Yield10Y:        tnx?.price ?? tnx?.regularMarketPrice ?? tnx?.previousClose ?? null,
  DXY_Change:      dxy?.percentChange,
  SMH_Change:      smh?.percentChange,
  IYT_Change:      iyt?.percentChange,
  XLK_Change:      sectorBySymbol["XLK"]?.percentChange,
  XLY_Change:      sectorBySymbol["XLY"]?.percentChange,
  XLF_Change:      sectorBySymbol["XLF"]?.percentChange,
  XLI_Change:      sectorBySymbol["XLI"]?.percentChange,
  XLB_Change:      sectorBySymbol["XLB"]?.percentChange,
  XLE_Change:      sectorBySymbol["XLE"]?.percentChange,
  XLV_Change:      sectorBySymbol["XLV"]?.percentChange,
  XLU_Change:      sectorBySymbol["XLU"]?.percentChange,
  XLRE_Change:     sectorBySymbol["XLRE"]?.percentChange,
  XLP_Change:      sectorBySymbol["XLP"]?.percentChange,
  XLC_Change:      sectorBySymbol["XLC"]?.percentChange,
};

return [{ json: { message, saveRow } }];

// Yahoo spark flat format: { "XLY": { timestamp, close, previousClose, chartPreviousClose }, ... }
const tickers = $('Tickers1').first().json.tickers;
const data    = $input.first().json;  // combined flat object from Combine Batches

const r = n => (n !== null && n !== undefined && !isNaN(n))
  ? Math.round(n * 100) / 100 : null;

return Object.entries(data).map(([sym, d]) => {
  const ticker = tickers.find(t => t.symbol === sym)
               || { symbol: sym, label: sym, category: 'Unknown' };

  const timestamps = d.timestamp || [];
  const closes     = d.close     || [];
  const prevClose  = r(d.chartPreviousClose || d.previousClose);

  // Find last pre-market bar (ET 4:00-9:30am = UTC 8:00-13:30)
  let preMarketPrice = null;
  let preMarketTime  = null;

  for (let i = timestamps.length - 1; i >= 0; i--) {
    const dt   = new Date(timestamps[i] * 1000);
    const utcH = dt.getUTCHours();
    const utcM = dt.getUTCMinutes();
    const isPM = (utcH > 8 || (utcH === 8)) && (utcH < 13 || (utcH === 13 && utcM < 30));
    if (isPM && closes[i] != null) {
      preMarketPrice = r(closes[i]);
      preMarketTime  = dt.toISOString();
      break;
    }
  }

  // Most recent valid close = last non-null entry
  const lastClose = r(closes.filter(c => c != null).slice(-1)[0]);

  let price, change, percentChange, priceSource;
  if (preMarketPrice != null) {
    price         = preMarketPrice;
    change        = prevClose != null ? r(preMarketPrice - prevClose) : null;
    percentChange = prevClose != null ? r(((preMarketPrice - prevClose) / prevClose) * 100) : null;
    priceSource   = 'PRE-MARKET';
  } else {
    price         = lastClose;
    change        = prevClose != null ? r(lastClose - prevClose) : null;
    percentChange = prevClose != null ? r(((lastClose - prevClose) / prevClose) * 100) : null;
    priceSource   = 'CLOSE';
  }

  const gapPct = (priceSource === 'PRE-MARKET' && price != null && prevClose != null)
    ? r(((price - prevClose) / prevClose) * 100)
    : null;

  return { json: {
    symbol:       sym,
    label:        ticker.label,
    category:     ticker.category,
    price,
    prevClose,
    change,
    percentChange,
    gapPct,
    priceSource,
    preMarketTime,
    high:          null,
    low:           null,
    volume:        null,
    avgVolume:     null,
  }};
});

// Split symbols into batches of <=20 (Yahoo spark limit)
const allSymbols = $json.symbols.split(',');
const BATCH_SIZE = 20;
const output = [];
for (let i = 0; i < allSymbols.length; i += BATCH_SIZE) {
  output.push({ json: { symbols: allSymbols.slice(i, i + BATCH_SIZE).join(',') } });
}
return output;

// Yahoo spark returns { ticker: { close, timestamp, previousClose, ... } }
// Merge both batch responses into one flat object
const combined = {};
for (const item of $input.all()) {
  Object.assign(combined, item.json);
}
return [{ json: combined }];
